const express = require('express');
const app = express();
const crypto = require('crypto');
const { randomUUID } = require('node:crypto');
const projectsRouter = require('./modules/projects/routes');
const tasksRouter = require('./modules/tasks/routes');
const membersRouter = require('./modules/members/routes');
const commentsRouter = require('./modules/comments/routes');
app.use(express.json());
app.get('/health', (req, res) => { res.json({ ok: true }); });
app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);
module.exports = app;

const express = require('express');
const router = express.Router();
const service = require('./service');
router.post('/', (req, res) => { if (!req.body.name) return sendError(res, 400, 'BadRequest', 'Name is required'); service.createProject(req, res); });
router.get('/:projectId/tasks', (req, res) => { const tasks = service.getTasksByProject(req.params.projectId);
if (!tasks) return sendError(res, 404, 'NotFound', 'Project not found'); res.json({ tasks }); });
module.exports = router;

const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');
router.post('/', (req, res) => { if (!req.body.userId || !req.body.role) return sendError(res, 400, 'BadRequest', 'UserId and role are required'); service.addMember(req, res); });
module.exports = router;

const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');
router.post('/', (req, res) => { if (!req.body.name) return sendError(res, 400, 'BadRequest', 'Name is required'); service.createTask(req, res); });
router.patch('/:taskId', (req, res) => { const task = service.updateTaskStatus(req.params.taskId, req.body.status);
if (!task) return sendError(res, 404, 'NotFound', 'Task not found'); res.json({ task }); });
router.get('/:projectId/tasks', (req, res) => { const tasks = service.getTasksByProject(req.params.projectId);
if (!tasks) return sendError(res, 404, 'NotFound', 'Project not found'); if (req.query.status === 'done') {
const doneTasks = tasks.filter(task => task.status === 'done'); res.json({ tasks: doneTasks }); }
else { res.json({ tasks }); }});
module.exports = router;

const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');
router.post('/', (req, res) => { if (!req.body.message) return sendError(res, 400, 'BadRequest', 'Message is required'); const commentId = randomUUID(); res.json({ comment: { id: commentId, message: req.body.message } }); });
module.exports = router;

class CustomError extends Error {
  constructor(code, message) { super(message); this.code = code; }
}
const sendError = (res, status, code, message) => res.status(status).json({ error: { code, message } });
module.exports = { CustomError, sendError };

const app = require('./app');
const port = process.env.PORT || 3000;

module.exports = app;

const createProject = (req, res) => {
  if (!req.body.name) return res.status(400).json({ error: { code: 'BadRequest', message: 'Name is required' } });
  const projectId = randomUUID();
  res.json({ project: { id: projectId, name: req.body.name } });
};
module.exports = { createProject };

const createTask = (req, res) => {
  if (!req.body.name) return res.status(400).json({ error: { code: 'BadRequest', message: 'Name is required' } });
  const taskId = randomUUID();
  res.json({ task: { id: taskId, name: req.body.name, status: 'todo' } });
};
const updateTaskStatus = (req, res) => {
  if (!['todo', 'done'].includes(req.body.status)) return res.status(400).json({ error: { code: 'BadRequest', message: 'Invalid status' } });
  const allowedStatuses = ['todo', 'done'];
  if (!allowedStatuses.includes(req.body.status)) return res.status(400).json({ error: { code: 'BadRequest', message: 'Invalid status' } });
  res.json({ task: { id: req.params.taskId, status: req.body.status } });
};
module.exports = { createTask, updateTaskStatus };

const addMember = (req, res) => {
  if (!req.body.userId || !req.body.role) return res.status(400).json({ error: { code: 'BadRequest', message: 'UserId and role are required' } });
  const memberId = randomUUID();
  res.json({ member: { id: memberId, userId: req.body.userId, role: req.body.role } });
};
module.exports = { addMember };

const addComment = (req, res) => {
  if (!req.body.message) return res.status(400).json({ error: { code: 'BadRequest', message: 'Message is required' } });
  const commentId = randomUUID();
  res.json({ comment: { id: commentId, message: req.body.message } });
};
module.exports = { addComment };
